-- 20260607_alchemy_immunity_family_riders.sql
-- DNDNext Alchemy v7: shared immunity elixirs, family condition riders, and selected Rare die-step sources.
-- Safe/idempotent. Run after the v6 expanded-budget/condition migration.
--
-- Merge notes:
--   * Elixir of X Immunity is one shared formula. The required fourth-slot counteragent
--     sets the condition and may raise the minimum finished brew rarity without adding Quality Steps.
--   * Core-family riders do not consume ingredient rarity budget and activate only in Poison/Bomb formulas.
--   * Rare die-step sources are deliberately scarce: Dreamspore Morel, Oathroot, and Nightfang Cap.

BEGIN;

ALTER TABLE public.recipes
  ADD COLUMN IF NOT EXISTS grants_immunities text[] NOT NULL DEFAULT '{}'::text[],
  ADD COLUMN IF NOT EXISTS formula_family text,
  ADD COLUMN IF NOT EXISTS theme_source text;

COMMENT ON COLUMN public.recipes.grants_immunities IS
  'Conditions the finished brew grants immunity to. Shared X-formulas resolve this from the selected fourth-slot component.';
COMMENT ON COLUMN public.recipes.formula_family IS
  'Shared player-facing formula family, such as Elixir of X Immunity or Potion of X Resistance.';
COMMENT ON COLUMN public.recipes.theme_source IS
  'Explains which selection sets X for a shared formula.';

-- Remove the superseded one-condition cure formulas. Their function is replaced by
-- Elixir of X Immunity, which both ends the chosen condition and grants immunity for 1 hour.
DELETE FROM public.recipes
WHERE lower(coalesce(discipline, recipe_type, '')) = 'alchemy'
  AND name IN ('Brightsight Wash','Clear-Mind Draught','Courage Draught','Heartguard Tonic','Nervewake Tonic','Potion of Unbinding','Purity Tonic','Stonebreak Draught');

DELETE FROM public.items_catalog
WHERE item_key IN ('alchemy:crafted:brightsight-wash','alchemy:crafted:clear-mind-draught','alchemy:crafted:courage-draught','alchemy:crafted:heartguard-tonic','alchemy:crafted:nervewake-tonic','alchemy:crafted:potion-of-unbinding','alchemy:crafted:purity-tonic','alchemy:crafted:stonebreak-draught')
   OR item_name IN ('Brightsight Wash','Clear-Mind Draught','Courage Draught','Heartguard Tonic','Nervewake Tonic','Potion of Unbinding','Purity Tonic','Stonebreak Draught');

