dition if present and grants immunity to Petrified for 1 hour.","tags":["alchemy","crafted","elixirs","immunity","petrified","very-rare","alchemy_codex_v7"],"alchemy":{"kind":"crafted_product","rarity":"Very Rare","craftingInput":false,"codexVersion":"alchemy-codex-v7-immunity-family-riders","mergeNote":"Sellable immunity-elixir reference card generated from the shared Elixir of X Immunity formula.","bonuses":{},"brewImpact":"","section":"Elixirs","conditionRiders":[],"curesConditions":["Petrified"],"grantsImmunities":["Petrified"],"duration":"1 hour","formulaFamily":"Elixir of X Immunity"},"positive_effects":["Immediately ends the Petrified condition if present and grants immunity to Petrified for 1 hour."]},"item_description":"Immediately ends the Petrified condition if present and grants immunity to Petrified for 1 hour."}]'::jsonb) AS x(
    item_key text,item_name text,item_type text,item_rarity text,
    price_gp numeric,merchant_tags jsonb,payload jsonb,item_description text
  )
), normalized AS (
  SELECT item_key,item_name,item_type,item_rarity,price_gp,
         COALESCE(ARRAY(SELECT jsonb_array_elements_text(merchant_tags)), ARRAY[]::text[]) AS merchant_tags,
         payload
  FROM seed
)
INSERT INTO public.items_catalog(item_key,item_name,item_type,item_rarity,price_gp,merchant_tags,payload)
SELECT seed.item_key,seed.item_name,seed.item_type,seed.item_rarity,seed.price_gp,seed.merchant_tags,seed.payload
FROM normalized seed
WHERE NOT EXISTS (SELECT 1 FROM public.items_catalog existing WHERE existing.item_key=seed.item_key);

-- Keep forage/player_plants rows synchronized for the nine core-family rider sources.
