ame":"Nightfang Cap","name":"Nightfang Cap","item_type":"Plant / Herb","uiType":"Plant / Herb","item_rarity":"Rare","rarity":"Rare","source":"DNDNext Alchemy Codex","flavor":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal.","item_description":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal.","alchemy":{"kind":"ingredient","family":"venom_poison","familyLabel":"Venom / Poison Plant","rarity":"Rare","slot":"Core herb","slotType":"core","craftDcReduction":4,"bonuses":{"dieSteps":1,"conditionRider":"Poisoned","conditionSave":"Constitution","conditionDuration":"1 minute","conditionRepeat":"end of each turn","riderEligibleSections":["Poisons","Bombs"],"riderBudgetCost":0},"brewImpact":"Die step +1 \u2022 Rider: Poisoned","physicalDescription":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal.","codexVersion":"alchemy-codex-v7-immunity-family-riders","mergeNote":"Canonical DB-synced alchemy codex row. Keep payload.alchemy stable for crafting, merchants, loot, player inventory, and future catalog exports.","riderSource":"core_family","riderBudgetNote":"Condition rider is thematic and does not consume the rarity attribute budget. It activates only in Poison or Bomb formulas."},"positive_effects":["Die step +1","Rider: Poisoned"],"tags":["alchemy","reagent","venom_poison","venom-poison-plant","rare","alchemy_codex_v2","alchemy_codex_v3","alchemy_codex_v6","alchemy_codex_v7"]},"item_description":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal."}]'::jsonb) AS x(
    item_key text,item_name text,item_type text,item_rarity text,
    price_gp numeric,merchant_tags jsonb,payload jsonb,item_description text
  )
), normalized AS (
  SELECT item_name,item_rarity,item_description,
         COALESCE(ARRAY(SELECT jsonb_array_elements_text(merchant_tags)), ARRAY[]::text[]) AS tags,
         payload->'alchemy' AS alchemy,
         COALESCE(ARRAY(SELECT jsonb_array_elements_text(COALESCE(payload->'positive_effects','[]'::jsonb))), ARRAY[]::text[]) AS positive_effects
  FROM seed
)
UPDATE public.plants target
SET rarity=seed.item_rarity,
    effect=COALESCE(seed.alchemy->>'brewImpact',''),
    tags=seed.tags,
    category='Plant / Herb',
    reagent_family=seed.alchemy->>'family',
    family_label=seed.alchemy->>'familyLabel',
    potency_rank=CASE seed.item_rarity WHEN 'Common' THEN 1 WHEN 'Uncommon' THEN 2 WHEN 'Rare' THEN 3 WHEN 'Very Rare' THEN 4 WHEN 'Legendary' THEN 5 ELSE 0 END,
    effect_family=seed.alchemy->>'family',
    positive_effects=seed.positive_effects,
    alchemy_notes=COALESCE(seed.alchemy->>'physicalDescription',seed.item_description),
    updated_at=now()
FROM normalized seed
WHERE lower(target.name)=lower(seed.item_name);

