ame":"Nightfang Cap","name":"Nightfang Cap","item_type":"Plant / Herb","uiType":"Plant / Herb","item_rarity":"Rare","rarity":"Rare","source":"DNDNext Alchemy Codex","flavor":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal.","item_description":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal.","alchemy":{"kind":"ingredient","family":"venom_poison","familyLabel":"Venom / Poison Plant","rarity":"Rare","slot":"Core herb","slotType":"core","craftDcReduction":4,"bonuses":{"dieSteps":1,"conditionRider":"Poisoned","conditionSave":"Constitution","conditionDuration":"1 minute","conditionRepeat":"end of each turn","riderEligibleSections":["Poisons","Bombs"],"riderBudgetCost":0},"brewImpact":"Die step +1 \u2022 Rider: Poisoned","physicalDescription":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal.","codexVersion":"alchemy-codex-v7-immunity-family-riders","mergeNote":"Canonical DB-synced alchemy codex row. Keep payload.alchemy stable for crafting, merchants, loot, player inventory, and future catalog exports.","riderSource":"core_family","riderBudgetNote":"Condition rider is thematic and does not consume the rarity attribute budget. It activates only in Poison or Bomb formulas."},"positive_effects":["Die step +1","Rider: Poisoned"],"tags":["alchemy","reagent","venom_poison","venom-poison-plant","rare","alchemy_codex_v2","alchemy_codex_v3","alchemy_codex_v6","alchemy_codex_v7"]},"item_description":"A black mushroom cap with toothlike white ridges underneath. It smells of damp leather and sour metal."}]'::jsonb) AS x(
    item_key text,item_name text,item_type text,item_rarity text,
    price_gp numeric,merchant_tags jsonb,payload jsonb,item_description text
  )
), normalized AS (
  SELECT item_name,item_rarity,item_description,
         COALESCE(ARRAY(SELECT jsonb_array_elements_text(merchant_tags)), ARRAY[]::text[]) AS tags,
         payload->'alchemy' AS alchemy,
         COALESCE(ARRAY(SELECT jsonb_array_elements_text(COALESCE(payload->'positive_effects','[]'::jsonb))), ARRAY[]::text[]) AS positive_effects
  FROM seed
)
INSERT INTO public.plants(name,rarity,found_in,effect,tags,category,forage_dc,reagent_family,family_label,potency_rank,effect_family,positive_effects,alchemy_notes,updated_at)
SELECT seed.item_name,seed.item_rarity,'DNDNext Alchemy Codex',COALESCE(seed.alchemy->>'brewImpact',''),seed.tags,'Plant / Herb',
       CASE seed.item_rarity WHEN 'Common' THEN 10 WHEN 'Uncommon' THEN 14 WHEN 'Rare' THEN 18 WHEN 'Very Rare' THEN 24 WHEN 'Legendary' THEN 30 ELSE 12 END,
       seed.alchemy->>'family',seed.alchemy->>'familyLabel',
       CASE seed.item_rarity WHEN 'Common' THEN 1 WHEN 'Uncommon' THEN 2 WHEN 'Rare' THEN 3 WHEN 'Very Rare' THEN 4 WHEN 'Legendary' THEN 5 ELSE 0 END,
       seed.alchemy->>'family',seed.positive_effects,COALESCE(seed.alchemy->>'physicalDescription',seed.item_description),now()
FROM normalized seed
WHERE NOT EXISTS (SELECT 1 FROM public.plants existing WHERE lower(existing.name)=lower(seed.item_name));

-- Shared immunity formula.
WITH seed AS (
  SELECT
    'Elixir of X Immunity'::text AS name,
    'Immediately ends the condition selected by the fourth-slot counteragent if present, then grants immunity to that condition for 1 hour.'::text AS description,
    'Alchemy'::text AS recipe_type,
    'Alchemy'::text AS discipline,
    'Uncommon'::text AS rarity,
    22::integer AS base_dc,
    'DNDNext Alchemy Formula Guide v7'::text AS source,
    ARRAY['alchemy','elixirs','immunity','shared_formula','alchemy_formula_v7']::text[] AS tags,
    '1 hour'::text AS duration,
    'Bonus Action to use or apply'::text AS use_text,
    'Immediately ends the chosen condition if present and grants immunity to that condition for 1 hour.'::text AS effect_text,
    1::integer AS output_quantity,
    1::integer AS batch_quantity,
    'Elixirs'::text AS alchemy_section,
    '[{"key":"immunity_elixir_core_1","role":"Restorative root","family":"root","min_rarity":"Uncommon","required":true},{"key":"immunity_elixir_core_2","role":"Clarity flower","family":"flower","min_rarity":"Uncommon","required":true},{"key":"immunity_elixir_core_3","role":"Purifying mineral","family":"mineral_salt_ash","min_rarity":"Uncommon","required":true},{"key":"immunity_elixir_modifier","role":"Condition counteragent","family":"any","slot_type":"modifier","required":true,"allowed_families":["enhancer","holy_vital","essence","monster_fluid"],"requires_condition_cure":true,"note":"Required fourth slot. The selected counteragent sets the condition immunity and may raise the minimum finished brew rarity."}]'::jsonb AS ingredient_slots,
    'root + flower + mineral_salt_ash'::text AS family_formula,
    ARRAY[]::text[] AS condition_riders,
    ARRAY['X']::text[] AS cures_conditions,
    ARRAY['X']::text[] AS grants_immunities,
    'Elixir of X Immunity'::text AS formula_family,
    'Required fourth-slot counteragent sets the condition and minimum brew rarity.'::text AS theme_source
)
UPDATE public.recipes target
SET description=seed.description,recipe_type=seed.recipe_type,discipline=seed.discipline,
    rarity=seed.rarity,base_dc=seed.base_dc,source=seed.source,tags=seed.tags,
    duration=seed.duration,use_text=seed.use_text,effect_text=seed.effect_text,
    output_quantity=seed.output_quantity,batch_quantity=seed.batch_quantity,
    alchemy_section=seed.alchemy_section,ingredient_slots=seed.ingredient_slots,
    family_formula=seed.family_formula,condition_riders=seed.condition_riders,
    cures_conditions=seed.cures_conditions,grants_immunities=seed.grants_immunities,
    formula_family=seed.formula_family,theme_source=seed.theme_source,updated_at=now()
FROM seed
WHERE lower(target.name)=lower(seed.name)
  AND lower(coalesce(target.discipline,target.recipe_type,''))='alchemy';

WITH seed AS (
  SELECT
    'Elixir of X Immunity'::text AS name,
    'Immediately ends the condition selected by the fourth-slot counteragent if present, then grants immunity to that condition for 1 hour.'::text AS description,
    'Alchemy'::text AS recipe_type,'Alchemy'::text AS discipline,'Uncommon'::text AS rarity,22::integer AS base_dc,
    'DNDNext Alchemy Formula Guide v7'::text AS source,
    ARRAY['alchemy','elixirs','immunity','shared_formula','alchemy_formula_v7']::text[] AS tags,
    '1 hour'::text AS duration,'Bonus Action to use or apply'::text AS use_text,
    'Immediately ends the chosen condition if present and grants immunity to that condition for 1 hour.'::text AS effect_text,
    1::integer AS output_quantity,1::integer AS batch_quantity,'Elixirs'::text AS alchemy_section,
    '[{"key":"immunity_elixir_core_1","role":"Restorative root","family":"root","min_rarity":"Uncommon","required":true},{"key":"immunity_elixir_core_2","role":"Clarity flower","family":"flower","min_rarity":"Uncommon","required":true},{"key":"immunity_elixir_core_3","role":"Purifying mineral","family":"mineral_salt_ash","min_rarity":"Uncommon","required":true},{"key":"immunity_elixir_modifier","role":"Condition counteragent","family":"any","slot_type":"modifier","required":true,"allowed_families":["enhancer","holy_vital","essence","monster_fluid"],"requires_condition_cure":true,"note":"Required fourth slot. The selected counteragent sets the condition immunity and may raise the minimum finished brew rarity."}]'::jsonb AS ingredient_slots,
    'root + flower + mineral_salt_ash'::text AS family_formula,
    ARRAY[]::text[] AS condition_riders,ARRAY['X']::text[] AS cures_conditions,
