INSERT INTO public.recipes(name,description,recipe_type,discipline,rarity,base_dc,source,tags,duration,use_text,effect_text,output_quantity,batch_quantity,alchemy_section,ingredient_slots,family_formula,condition_riders,cures_conditions,grants_immunities,formula_family,theme_source,updated_at)
SELECT seed.name,seed.description,seed.recipe_type,seed.discipline,seed.rarity,seed.base_dc,seed.source,seed.tags,seed.duration,seed.use_text,seed.effect_text,seed.output_quantity,seed.batch_quantity,seed.alchemy_section,seed.ingredient_slots,seed.family_formula,seed.condition_riders,seed.cures_conditions,seed.grants_immunities,seed.formula_family,seed.theme_source,now()
FROM seed
WHERE NOT EXISTS (
  SELECT 1 FROM public.recipes existing
  WHERE lower(existing.name)=lower(seed.name)
    AND lower(coalesce(existing.discipline,existing.recipe_type,''))='alchemy'
);

-- Annotate all shared X-formulas so future UI/database merges can consolidate them safely.
WITH seed AS (
  SELECT *
