tion":"1 hour","effect":"The target chooses Constitution or Strength before rolling. On a failed save, Strength is reduced by 1d6 temporarily.","use":"Bonus Action to use or apply","notes":"","formula_family":"Poison of X Weakening","theme_source":"Named formula variant sets the attacked ability."},{"name":"Poison of Wisdom Weakening","section":"Poisons","rarity":"Rare","cores":["venom_poison","moss_lichen","flower"],"modifier":"Optional fourth slot: venom, bile, essence, or monster component that adds a rider or die step.","modifier_required":false,"allowed":["monster_fluid","essence","enhancer"],"duration":"1 hour","effect":"The target chooses Constitution or Wisdom before rolling. On a failed save, Wisdom is reduced by 1d6 temporarily.","use":"Bonus Action to use or apply","notes":"","formula_family":"Poison of X Weakening","theme_source":"Named formula variant sets the attacked ability."},{"name":"Elixir of Charisma","section":"Elixirs","rarity":"Uncommon","cores":["flower","sap_resin","mineral_salt_ash"],"modifier":"Optional fourth slot: enhancer, holy/vital component, essence, or monster-derived ability twist.","modifier_required":false,"allowed":["enhancer","holy_vital","essence","monster_fluid"],"duration":"1 hour","effect":"Charisma increases by 1d4 for the duration.","use":"Bonus Action to use or apply","notes":"","formula_family":"Elixir of X Ability","theme_source":"Named formula variant sets the ability."},{"name":"Elixir of Constitution","section":"Elixirs","rarity":"Uncommon","cores":["root","mushroom","moss_lichen"],"modifier":"Optional fourth slot: enhancer, holy/vital component, essence, or monster-derived ability twist.","modifier_required":false,"allowed":["enhancer","holy_vital","essence","monster_fluid"],"duration":"1 hour","effect":"Constitution increases by 1d4 for the duration.","use":"Bonus Action to use or apply","notes":"","formula_family":"Elixir of X Ability","theme_source":"Named formula variant sets the ability."},{"name":"Elixir of Dexterity","section":"Elixirs","rarity":"Uncommon","cores":["leaf_vine","flower","sap_resin"],"modifier":"Optional fourth slot: enhancer, holy/vital component, essence, or monster-derived ability twist.","modifier_required":false,"allowed":["enhancer","holy_vital","essence","monster_fluid"],"duration":"1 hour","effect":"Dexterity increases by 1d4 for the duration.","use":"Bonus Action to use or apply","notes":"","formula_family":"Elixir of X Ability","theme_source":"Named formula variant sets the ability."},{"name":"Elixir of Intelligence","section":"Elixirs","rarity":"Uncommon","cores":["flower","mineral_salt_ash","root"],"modifier":"Optional fourth slot: enhancer, holy/vital component, essence, or monster-derived ability twist.","modifier_required":false,"allowed":["enhancer","holy_vital","essence","monster_fluid"],"duration":"1 hour","effect":"Intelligence increases by 1d4 for the duration.","use":"Bonus Action to use or apply","notes":"","formula_family":"Elixir of X Ability","theme_source":"Named formula variant sets the ability."},{"name":"Elixir of Strength","section":"Elixirs","rarity":"Uncommon","cores":["root","thorn_bark_wood","mushroom"],"modifier":"Optional fourth slot: enhancer, holy/vital component, essence, or monster-derived ability twist.","modifier_required":false,"allowed":["enhancer","holy_vital","essence","monster_fluid"],"duration":"1 hour","effect":"Strength increases by 1d4 for the duration.","use":"Bonus Action to use or apply","notes":"","formula_family":"Elixir of X Ability","theme_source":"Named formula variant sets the ability."},{"name":"Elixir of Wisdom","section":"Elixirs","rarity":"Uncommon","cores":["moss_lichen","flower","root"],"modifier":"Optional fourth slot: enhancer, holy/vital component, essence, or monster-derived ability twist.","modifier_required":false,"allowed":["enhancer","holy_vital","essence","monster_fluid"],"duration":"1 hour","effect":"Wisdom increases by 1d4 for the duration.","use":"Bonus Action to use or apply","notes":"","formula_family":"Elixir of X Ability","theme_source":"Named formula variant sets the ability."},{"name":"Elixir of X Immunity","section":"Elixirs","rarity":"Uncommon","cores":["root","flower","mineral_salt_ash"],"modifier":"Required fourth slot: a condition counteragent that sets X and the minimum finished brew rarity.","modifier_required":true,"allowed":["enhancer","holy_vital","essence","monster_fluid"],"duration":"1 hour","effect":"Immediately ends the condition set by the chosen counteragent if it is already present, then grants immunity to that condition for 1 hour.","use":"Bonus Action to use or apply","condition_riders":[],"cures_conditions":["X"],"grants_immunities":["X"],"rider_save":"","rider_duration":"","rider_repeat_save":"","formula_family":"Elixir of X Immunity","theme_source":"Required fourth-slot counteragent sets the condition and minimum brew rarity.","notes":"Shared immunity formula. The condition counteragent does not add Quality Steps; it can raise the minimum finished rarity."}]'::jsonb) AS x(
    name text,section text,rarity text,cores jsonb,modifier text,modifier_required boolean,
    allowed_families jsonb,condition_riders jsonb,cures_conditions jsonb,grants_immunities jsonb,
    rider_save text,rider_duration text,rider_repeat_save text,formula_family text,theme_source text
  )
)
UPDATE public.recipes target
SET formula_family=seed.formula_family,
    theme_source=seed.theme_source,
    grants_immunities=COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.grants_immunities)),ARRAY[]::text[]),
    updated_at=now()
FROM seed
WHERE lower(target.name)=lower(seed.name)
  AND lower(coalesce(target.discipline,target.recipe_type,''))='alchemy';

CREATE INDEX IF NOT EXISTS recipes_formula_family_idx
  ON public.recipes(formula_family)
  WHERE formula_family IS NOT NULL;

COMMIT;

